import { NavLink } from "react-router-dom";
import { LayoutDashboard, ShieldAlert, AlertTriangle, FileText, Search } from "lucide-react";
import styles from "./Sidebar.module.css";

export default function Sidebar() {
  const routes = [
    { path: "/", label: "Dashboard", icon: LayoutDashboard },
    { path: "/alerts", label: "Alerts", icon: ShieldAlert },
    { path: "/incidents", label: "Incidents", icon: AlertTriangle },
    { path: "/logs", label: "Logs Explorer", icon: FileText },
    { path: "/search", label: "Search", icon: Search },
  ];

  return (
    <div className={styles.sidebar}>
      <div className={styles.logoContainer}>
        <h2>Vigilant AI</h2>
        <span className={styles.socBadge}>SOC</span>
      </div>

      <nav className={styles.nav}>
        {routes.map((r) => (
          <NavLink
            key={r.path}
            to={r.path}
            className={({ isActive }) =>
              isActive ? \`\${styles.navItem} \${styles.navItemActive}\` : styles.navItem
            }
          >
            <r.icon className={styles.icon} size={20} />
            {r.label}
          </NavLink>
        ))}
      </nav>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { mockAPI } from "../services/mockService";
import { ArrowLeft, Clock, ShieldAlert, FileText, UserCircle } from "lucide-react";
import styles from "./AlertDetailsPage.module.css";

export default function AlertDetailsPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [alert, setAlert] = useState(null);
  const [newNote, setNewNote] = useState("");

  useEffect(() => {
    mockAPI.getAlertById(id).then(setAlert).catch(() => navigate("/alerts"));
  }, [id, navigate]);

  const handleStatusChange = async (e) => {
    const updated = await mockAPI.updateAlertStatus(id, e.target.value);
    setAlert(updated);
  };

  const handleAssign = async (e) => {
    const updated = await mockAPI.assignAlert(id, e.target.value);
    setAlert(updated);
  };

  const handleAddNote = async () => {
    if (!newNote.trim()) return;
    const updated = await mockAPI.addNote(id, newNote);
    setAlert(updated);
    setNewNote("");
  };

  if (!alert) return <div className={styles.loading}>Loading alert details...</div>;

  return (
    <div className={styles.container}>
      <div className={styles.topBar}>
        <button onClick={() => navigate("/alerts")} className={styles.backBtn}>
          <ArrowLeft size={16} /> Back to Alerts
        </button>
      </div>

      <div className={styles.header}>
        <div className={styles.titleSection}>
          <span className={\`\${styles.severityBadge} \${styles[alert.severity.toLowerCase()]}\`}>
            {alert.severity}
          </span>
          <h1>{alert.type}</h1>
        </div>
        <div className={styles.controls}>
          <select value={alert.status} onChange={handleStatusChange} className={styles.selectBox}>
            <option value="Open">Open</option>
            <option value="In Progress">In Progress</option>
            <option value="Resolved">Resolved</option>
            <option value="False Positive">False Positive</option>
          </select>
          <select value={alert.assignee || ""} onChange={handleAssign} className={styles.selectBox}>
            <option value="">Unassigned</option>
            <option value="Alice SOC">Alice SOC</option>
            <option value="Bob Admin">Bob Admin</option>
          </select>
        </div>
      </div>

      <div className={styles.gridContainer}>
        {/* LEFT COLUMN */}
        <div className={styles.leftCol}>
          <div className={styles.card}>
            <h3><ShieldAlert size={16}/> Metadata</h3>
            <div className={styles.metaGrid}>
              <div className={styles.metaRow}><span>Event ID</span><strong>{alert.id}</strong></div>
              <div className={styles.metaRow}><span>Source IP</span><strong className={styles.mono}>{alert.sourceIp}</strong></div>
              <div className={styles.metaRow}><span>Dest IP</span><strong className={styles.mono}>{alert.destIp}</strong></div>
              <div className={styles.metaRow}><span>Timestamp</span><strong>{new Date(alert.timestamp).toLocaleString()}</strong></div>
            </div>
          </div>

          <div className={styles.card}>
            <h3><FileText size={16}/> Raw Log Substring</h3>
            <pre className={styles.logViewer}>{alert.rawLog}</pre>
          </div>
        </div>

        {/* RIGHT COLUMN */}
        <div className={styles.rightCol}>
          <div className={styles.card}>
            <h3><Clock size={16}/> Investigation Notes</h3>
            <div className={styles.notesContainer}>
              {alert.notes.length === 0 && <p className={styles.empty}>No notes added yet.</p>}
              {alert.notes.map(n => (
                <div key={n.id} className={styles.noteBox}>
                  <div className={styles.noteHeader}>
                    <span><UserCircle size={14}/> {n.author}</span>
                    <small>{new Date(n.timestamp).toLocaleTimeString()}</small>
                  </div>
                  <p>{n.text}</p>
                </div>
              ))}
            </div>

            <div className={styles.addNoteBox}>
              <textarea 
                value={newNote} 
                onChange={e => setNewNote(e.target.value)}
                placeholder="Add investigation details..."
                className={styles.textarea}
              />
              <button onClick={handleAddNote} className={styles.btnPrimary}>Add Note</button>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { mockAPI } from "../services/mockService";
import { Search, Filter } from "lucide-react";
import styles from "./AlertsPage.module.css";

export default function AlertsPage() {
  const [alerts, setAlerts] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    mockAPI.getAlerts().then(setAlerts);
  }, []);

  return (
    <div className={styles.container}>
      <div className={styles.headerRow}>
        <h1 className={styles.pageTitle}>Alerts</h1>
        <div className={styles.controls}>
          <div className={styles.searchBox}>
            <Search size={16} className={styles.icon} />
            <input type="text" placeholder="Search IP or rules..." className={styles.searchInput} />
          </div>
          <button className={styles.filterBtn}>
            <Filter size={16} /> Filters
          </button>
        </div>
      </div>

      <div className={styles.tableContainer}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Severity</th>
              <th>Type</th>
              <th>Status</th>
              <th>Assignee</th>
              <th>Source IP</th>
              <th>Timestamp</th>
            </tr>
          </thead>
          <tbody>
            {alerts.map((alert) => (
              <tr key={alert.id} onClick={() => navigate(\`/alerts/\${alert.id}\`)}>
                <td>
                  <span className={\`\${styles.severityBadge} \${styles[alert.severity.toLowerCase()]}\`}>
                    {alert.severity}
                  </span>
                </td>
                <td className={styles.alertType}>{alert.type}</td>
                <td>
                  <span className={\`\${styles.statusBadge} \${styles[alert.status.replace(" ", "").toLowerCase()]}\`}>
                     {alert.status}
                  </span>
                </td>
                <td className={styles.assignee}>{alert.assignee || "Unassigned"}</td>
                <td className={styles.ipFont}>{alert.sourceIp}</td>
                <td className={styles.timeFont}>{new Date(alert.timestamp).toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { mockAPI } from "../services/mockService";
import { Calendar, Link } from "lucide-react";
import styles from "./IncidentsPage.module.css";

export default function IncidentsPage() {
  const [incidents, setIncidents] = useState([]);

  useEffect(() => {
    mockAPI.getIncidents().then(setIncidents);
  }, []);

  return (
    <div className={styles.container}>
      <h1 className={styles.pageTitle}>Incident Management</h1>
      <p className={styles.subtitle}>Groups of related alerts correlated by the SIEM engine.</p>

      <div className={styles.grid}>
        {incidents.map(inc => (
          <div key={inc.id} className={styles.incidentCard}>
            <div className={styles.cardHeader}>
              <span className={\`\${styles.severityBadge} \${styles[inc.severity.toLowerCase()]}\`}>
                {inc.severity}
              </span>
              <span className={\`\${styles.statusBadge} \${inc.status === 'Active' ? styles.active : styles.investigating}\`}>
                {inc.status}
              </span>
            </div>

            <h3 className={styles.cardTitle}>{inc.name}</h3>
            <p className={styles.cardDesc}>{inc.description}</p>

            <div className={styles.cardFooter}>
              <div className={styles.footerItem}>
                <Link size={14} />
                <span>{inc.alertsCount} Alerts</span>
              </div>
              <div className={styles.footerItem}>
                <Calendar size={14} />
                <span>{new Date(inc.timestamp).toLocaleDateString()}</span>
              </div>
              <button className={styles.btnAction}>Investigate</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
